CITIES_LAYERS_JS = (
    'const CITIES=' + CITIES_JS + ';\n'
    'map.addSource("cities",{type:"geojson",data:{type:"FeatureCollection",\n'
    '  features:CITIES.map(function(c){ return {type:"Feature",\n'
    '    geometry:{type:"Point",coordinates:[c[1],c[2]]},\n'
    '    properties:{name:c[0],tier:c[3]}}; })}});\n'
    'const CITY_DOT_R={1:3,2:2.2,3:1.6};\n'
    'const CITY_MINZ={1:0,2:2,3:3.5};\n'
    '[1,2,3].forEach(function(tr){\n'
    '  map.addLayer({id:"cities-dot-"+tr,type:"circle",source:"cities",minzoom:CITY_MINZ[tr],\n'
    '    filter:["==",["get","tier"],tr],\n'
    '    layout:{visibility:"none"},\n'
    '    paint:{"circle-radius":CITY_DOT_R[tr],"circle-color":"#3a3226",\n'
    '      "circle-stroke-width":1,"circle-stroke-color":"rgba(255,250,240,0.85)"}});\n'
    '});\n'
    'const CITY_FONT={1:"Noto Sans Bold",2:"Noto Sans Regular",3:"Noto Sans Italic"};\n'
    'const CITY_SIZE={1:13,2:11,3:9.5};\n'
    'const CITY_SORT={1:-3,2:-2,3:-1};\n'
    '[1,2,3].forEach(function(tr){\n'
    '  map.addLayer({id:"cities-label-"+tr,type:"symbol",source:"cities",minzoom:CITY_MINZ[tr],\n'
    '    filter:["==",["get","tier"],tr],\n'
    '    layout:{"text-field":["get","name"],"text-font":[CITY_FONT[tr]],\n'
    '      "text-size":CITY_SIZE[tr],"text-offset":[0,0.8],"text-anchor":"top",\n'
    '      "text-max-width":8,"text-padding":3,"symbol-sort-key":CITY_SORT[tr],\n'
    '      "symbol-placement":"point","text-allow-overlap":false,"visibility":"none"},\n'
    '    paint:{"text-color":"#3a3226","text-halo-color":"rgba(255,255,255,0.7)","text-halo-width":1.1}});\n'
    '});\n'
)

EDITS = [
    (
        "insert CITIES array + 6 cities layers after country-labels",
        'paint:{"text-color":"#3a3226","text-halo-color":"rgba(255,255,255,0.55)","text-halo-width":1.1}});\nwindow.USE_3D_LABELS=false;',
        'paint:{"text-color":"#3a3226","text-halo-color":"rgba(255,255,255,0.55)","text-halo-width":1.1}});\n' + CITIES_LAYERS_JS + 'window.USE_3D_LABELS=false;',
        "replace",
        'map.addSource("cities"',
    ),
    (
        "toggle cities layers visibility alongside country-glow in setLayer()",
        '{ const _isCountriesRef=(key==="countries"&&!subOn);   // relief-map look: colored glow hugging each border\n'
        '    if(map.getLayer("country-glow-soft")) map.setLayoutProperty("country-glow-soft","visibility",_isCountriesRef?"visible":"none");\n'
        '    if(map.getLayer("country-glow-tight")) map.setLayoutProperty("country-glow-tight","visibility",_isCountriesRef?"visible":"none"); }\n'
        '  drawLegend(key);\n'
        '}',
        '{ const _isCountriesRef=(key==="countries"&&!subOn);   // relief-map look: colored glow hugging each border\n'
        '    if(map.getLayer("country-glow-soft")) map.setLayoutProperty("country-glow-soft","visibility",_isCountriesRef?"visible":"none");\n'
        '    if(map.getLayer("country-glow-tight")) map.setLayoutProperty("country-glow-tight","visibility",_isCountriesRef?"visible":"none");\n'
        '    [1,2,3].forEach(function(tr){\n'
        '      if(map.getLayer("cities-dot-"+tr)) map.setLayoutProperty("cities-dot-"+tr,"visibility",_isCountriesRef?"visible":"none");\n'
        '      if(map.getLayer("cities-label-"+tr)) map.setLayoutProperty("cities-label-"+tr,"visibility",_isCountriesRef?"visible":"none");\n'
        '    }); }\n'
        '  drawLegend(key);\n'
        '}',
        "replace",
        'cities-dot-"+tr,"visibility"',
    ),
]

results = []
for name, old, new, mode, sentinel in EDITS:
    if sentinel in text:
        results.append((name, "already-applied"))
        continue
    if old not in text:
        results.append((name, "ANCHOR-NOT-FOUND"))
        continue
    text = text.replace(old, new, 1)
    results.append((name, "patched"))

open(OUT, "w", encoding="utf-8").write(text)

ok = True
for name, status in results:
    print("  [%16s] %s" % (status, name))
    if status == "ANCHOR-NOT-FOUND":
        ok = False

print("OK: cities layer applied" if ok else "WARN: one or more anchors not found - review before deploying")
sys.exit(0 if ok else 1)
